import { MessageEvent } from '@nitrots/nitro-renderer';
import { BlackjackMessageParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/roleplay/BlackJackMessage';

export class BlackjackMessageEvent extends MessageEvent {
    constructor(callBack: (event: BlackjackMessageEvent) => void) {
        super(callBack, BlackjackMessageParser);
    }
    public getParser(): BlackjackMessageParser {
        return this.parser as BlackjackMessageParser;
    }
}
